// src/pages/admin/AdminPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI } from '../../components/UI';
import { calcResolutionRate, avgResolutionTime } from '../../utils/helpers';
import LiveMap from '../../components/LiveMap';

export default function AdminPortal() {
  const { complaints } = useApp();
  const [activeTab, setActiveTab] = useState('DASHBOARD');

  // Multi-Station Analytics Compute
  const totalTickets = complaints.length;
  const globalSuccessRate = calcResolutionRate(complaints);
  const totalAvgTime = avgResolutionTime(complaints);

  const navItems = [
    { key: 'DASHBOARD', label: 'National Dashboard', icon: '📊', count: 0 },
    { key: 'REGISTRY', label: 'All India Ledger', icon: '🗃️', count: totalTickets }
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="HQ Command Matrix" subtitle="Indian Railways Clean Net" 
        navItems={navItems} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'Executive Director', role: 'Railway Board HQ', initials: 'RB', avatarColor: '#B71C1C' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        {activeTab === 'DASHBOARD' ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16, flex: 1 }}>
            {/* National Level Critical KPIs */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14 }}>
              <KPI title="TOTAL NATIONAL TICKETS" value={totalTickets} subtitle="Across all Zonal Systems" />
              <KPI title="GLOBAL RESOLUTION INDICES" value={`${globalSuccessRate}%`} color="#2E7D32" subtitle="Target Baseline: 95%" />
              <KPI title="NETWORK REFLEX LATENCY" value={`${totalAvgTime} Mins`} color="#4527A0" subtitle="Mean Time to Resolution" />
            </div>
            
            {/* Country scale map showing distributed alerts */}
            <div style={{ flex: 1 }}>
              <LiveMap complaints={complaints} />
            </div>
          </div>
        ) : (
          <div style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 12, overflow: 'hidden', display: 'flex', flexDirection: 'column', flex: 1 }}>
            <div style={{ overflowY: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', fontSize: 13 }}>
                <thead>
                  <tr style={{ background: '#F7F9FC', borderBottom: '1px solid #DDE3E9', color: '#546E7A' }}>
                    <th style={{ padding: 12 }}>TICKET ID</th>
                    <th style={{ padding: 12 }}>ZONAL STATION</th>
                    <th style={{ padding: 12 }}>EXACT AREA</th>
                    <th style={{ padding: 12 }}>GARBAGE TYPE</th>
                    <th style={{ padding: 12 }}>STATUS</th>
                    <th style={{ padding: 12 }}>ASSIGNED FORCE</th>
                  </tr>
                </thead>
                <tbody>
                  {complaints.map(c => (
                    <tr key={c.id} style={{ borderBottom: '1px solid #ECEFF1', transition: '0.15s' }}>
                      <td style={{ padding: 12, fontFamily: 'monospace', fontWeight: 600, color: '#1565C0' }}>{c.customTicketId}</td>
                      <td style={{ padding: 12 }}>
                        <div style={{ fontWeight: 600 }}>{c.station?.name}</div>
                        <div style={{ fontSize: 10, color: '#7A8FA6' }}>{c.station?.zone} ({c.station?.code})</div>
                      </td>
                      <td style={{ padding: 12 }}>{c.area}</td>
                      <td style={{ padding: 12 }}>{c.emoji} {c.gtype}</td>
                      <td style={{ padding: 12 }}>
                        <span style={{ padding: '2px 6px', borderRadius: 4, fontSize: 11, fontWeight: 700, background: c.status === 'NEW' ? '#FFF3E0' : '#E8F5E9', color: c.status === 'NEW' ? '#E65100' : '#2E7D32' }}>
                          {c.status}
                        </span>
                      </td>
                      <td style={{ padding: 12, color: '#4527A0', fontWeight: 500 }}>{c.assignedTo || 'Unallocated Team'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
